import React, { useEffect, useState } from "react";
import axios from "axios";
import jsPDF from "jspdf";
import "./MealPlan.css";

export default function MealPlan() {
  const [plans, setPlans] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/dietplan/my-plans", {
        headers: {
          Authorization: "Bearer " + localStorage.getItem("token"),
        },
      })
      .then((res) => setPlans(res.data))
      .catch((err) => console.log(err));
  }, []);

  const downloadPDF = (plan) => {
    const pdf = new jsPDF();
    let y = 10;

    pdf.text(`Meal Plan for ${plan.patientName}`, 10, y);
    y += 8;

    pdf.text(`Condition: ${plan.condition}`, 10, y);
    y += 6;
    pdf.text(`Goal: ${plan.goal}`, 10, y);
    y += 6;
    pdf.text(`Calories: ${plan.calories} kcal`, 10, y);
    y += 10;

    Object.entries(plan.meals).forEach(([meal, items]) => {
      pdf.text(meal.toUpperCase(), 10, y);
      y += 6;
      items.forEach((f) => {
        pdf.text(`- ${f.item} (${f.quantity})`, 14, y);
        y += 6;
      });
      y += 4;
    });

    if (plan.avoid?.length) {
      pdf.text("Foods to Avoid:", 10, y);
      y += 6;
      plan.avoid.forEach((a) => {
        pdf.text(`- ${a}`, 14, y);
        y += 6;
      });
    }

    pdf.save(`${plan.patientName}_Meal_Plan.pdf`);
  };

  if (plans.length === 0) {
    return <h4 className="text-center mt-5">No Meal Plans Yet</h4>;
  }

  return (
    <div className="meal-container my-4">
      <h2 className="text-center mb-4">Your AI Meal Plans</h2>

      {plans.map((plan, i) => (
        <div key={i} className="plan-card">
          <div className="plan-header">
            <h4>{plan.patientName}</h4>
            <button
              className="download-btn"
              onClick={() => downloadPDF(plan)}
            >
              Download PDF
            </button>
          </div>

          <div className="plan-meta">
            Condition: {plan.condition} | Goal: {plan.goal} | Calories:{" "}
            {plan.calories} kcal
          </div>

          {Object.entries(plan.meals).map(([meal, items]) => (
            <div key={meal} className="meal-section">
              <h5>{meal}</h5>
              <ul>
                {items.map((f, idx) => (
                  <li key={idx}>
                    {f.item} — <strong>{f.quantity}</strong>
                  </li>
                ))}
              </ul>
            </div>
          ))}

          {plan.avoid?.length > 0 && (
            <div className="mt-3">
              {plan.avoid.map((a, idx) => (
                <span key={idx} className="badge-avoid">
                  {a}
                </span>
              ))}
            </div>
          )}

          {plan.notes?.length > 0 && (
            <div className="mt-3">
              {plan.notes.map((n, idx) => (
                <span key={idx} className="badge-note">
                  {n}
                </span>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}
